import{_ as e,o,c as r,a5 as l}from"./chunks/framework.B5tqjWbr.js";const P=JSON.parse('{"title":"学习记录 #0005：锁相环（PLL）技术——电网同步的核心","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0005：锁相环（PLL）技术——电网同步的核心","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第5课 — 锁相环（PLL）技术 **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0005-phase-locked-loop.md","filePath":"content/power/archive/old-learning-records/0005-phase-locked-loop.md","lastUpdated":null}'),t={name:"content/power/archive/old-learning-records/0005-phase-locked-loop.md"};function i(s,a,n,c,d,h){return o(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="学习记录-0005-锁相环-pll-技术——电网同步的核心" tabindex="-1">学习记录 #0005：锁相环（PLL）技术——电网同步的核心 <a class="header-anchor" href="#学习记录-0005-锁相环-pll-技术——电网同步的核心" aria-label="Permalink to &quot;学习记录 #0005：锁相环（PLL）技术——电网同步的核心&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第5课 — 锁相环（PLL）技术 <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>UPS必须锁相</strong>：相位差&gt;5°并网可能损坏设备，PLL提供θ和f用于dq控制和同步切换</li><li><strong>SRF-PLL核心</strong>：Clarke→Park→PI→VCO，vq=0表示锁相成功（vq=V·sin(φ-θ)）</li><li><strong>单相用SOGI-PLL</strong>：SOGI从单相信号生成正交对v&#39;/qv&#39;，等效vα/vβ，然后套用SRF</li><li><strong>SOGI传递函数</strong>：Hα=kωs/(s²+kωs+ω²)同相，Hβ=kω²/(s²+kωs+ω²)正交，k=√2最佳折中</li><li><strong>Tustin离散化</strong>：SOGI变成二阶IIR滤波器，系数随ω变化需动态更新</li><li><strong>不平衡问题</strong>：负序在dq坐标系产生2倍频波动，SRF-PLL无法处理→用DSOGI-PLL</li></ol><h2 id="代码要点" tabindex="-1">代码要点 <a class="header-anchor" href="#代码要点" aria-label="Permalink to &quot;代码要点&quot;">​</a></h2><ul><li>SRF-PLL：Clarke→Park→归一化vq→PI→VCO，约30行核心代码</li><li>SOGI-PLL：IIR滤波→Park→归一化vq→PI→VCO→反馈ω到SOGI更新系数</li><li>sin/cos优化：查表法或CORDIC，不要在ISR中调用sinf/cosf</li></ul><h2 id="待深入问题" tabindex="-1">待深入问题 <a class="header-anchor" href="#待深入问题" aria-label="Permalink to &quot;待深入问题&quot;">​</a></h2><ul><li>[ ] DSOGI-PLL的正负序分离具体怎么实现？</li><li>[ ] FLL（频率锁定环）和PLL的区别与配合？</li><li>[ ] sin/cos查表法的精度和速度权衡？</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第6课：ADC采样技术</p>',10)])])}const p=e(t,[["render",i]]);export{P as __pageData,p as default};
